import React from "react"
import dayjs from "dayjs"
import { graphql, useStaticQuery } from "gatsby"
import useAxios from "axios-hooks"
import { css } from "@emotion/react"
import { MDRender } from "../components/mdRender"
import Layout from "../components/layout"

const ThinkPage = (props) => {
  const { site } = useStaticQuery(
    graphql`
      query {
        site {
          siteMetadata {
            title
          }
        }
      }
    `
  )
  const [{ data, loading, error }] = useAxios("/open/think/list?uid=888888")
  console.log(data, loading, error)
  return (
    <Layout location={props.location} title={site.siteMetadata.title}>
      <section id="projects">
        {loading ? (
          <span className="dotting">...</span>
        ) : (
          <ul className="project-list">
            {data.map((item, index) => {
              return (
                <li
                  css={css`
                    span {
                      color: #2bbc8a;
                    }
                    p {
                      margin-top: 0;
                    }
                    img {
                      max-width: 100%;
                      margin-top: 5px;
                      border-radius: 2px;
                      border: 1px solid #4e4e4e;
                    }
                  `}
                  className="project-item"
                  key={item.id}
                >
                  {index !== 0 && (
                    <div
                      css={css`
                        margin: 12px 0;
                      `}
                    />
                  )}
                  <span>{dayjs(item.cts).format(`YYYY-MM-DD HH:mm`)}</span>
                  <MDRender md={item.text} />
                </li>
              )
            })}
          </ul>
        )}
      </section>
    </Layout>
  )
}

export default ThinkPage
